"import json
import os

prev_log = "/Users/paulpolsulintaboon/.gemini/antigravity/brain/59119761-b490-421b-b15d-46f12f5c4158/.system_generated/logs/transcript.jsonl"
curr_log = "/Users/paulpolsulintaboon/.gemini/antigravity/brain/247e75b9-4826-40df-8e90-5fa35311e2ea/.system_generated/logs/transcript.jsonl"

os.makedirs("extracted_edits", exist_ok=True)

def process_log(log_path, label):
    if not os.path.exists(log_path):
        print(f"Log {log_path} does not exist.")
        return
    with open(log_path, 'r', encoding='utf-8') as f:
        for idx, line in enumerate(f):
            try:
                data = json.loads(line)
            except:
                continue
            if data.get('type') == 'PLANNER_RESPONSE':
                for tc_idx, tc in enumerate(data.get('tool_calls', [])):
                    name = tc.get('name')
                    args = tc.get('args', {})
                    is_settings = False
                    if name == 'replace_file_content':
                        is_settings = 'SettingsPortal.tsx' in args.get('TargetFile', '')
                    elif name == 'write_to_file':
                        is_settings = 'SettingsPortal.tsx' in args.get('TargetFile', '')
                    elif name == 'multi_replace_file_content':
                        is_settings = 'SettingsPortal.tsx' in args.get('TargetFile', '')

                    if is_settings:
                        filename = f"extracted_edits/{label}_step_{idx}_tc_{tc_idx}_{name}.json"
                        with open(filename, 'w', encoding='utf-8') as out:
                            json.dump(tc, out, indent=2, ensure_ascii=False)
                        print(f"Saved {name} at step {idx} to {filename}")

process_log(prev_log, "prev")
process_log(curr_log, "curr")
print("Extraction complete!")
"
